// Build proposal context from prospect data and discovery call notes
const prospect = $input.first().json;
const request = $('Generate Proposal Request').first().json;

const f = prospect.fields || {};

// Calculate recommended package based on company size
let recommendedPackage = 'starter';
let monthlyPrice = 497;
let setupFee = 997;

const reviewCount = f['Review Count'] || 0;
const hasCommunicationPain = f['Has Communication Pain'] || false;

if (reviewCount > 200 || request.package === 'growth') {
  recommendedPackage = 'growth';
  monthlyPrice = 997;
  setupFee = 1997;
} else if (reviewCount > 500 || request.package === 'scale') {
  recommendedPackage = 'scale';
  monthlyPrice = 1997;
  setupFee = 2997;
}

// Calculate ROI projections
const avgJobValue = request.avgJobValue || 350;
const missedCallsPerWeek = request.missedCallsPerWeek || 15;
const conversionRate = 0.3; // 30% of answered calls become jobs

const monthlyMissedCalls = missedCallsPerWeek * 4;
const recoverableJobs = Math.round(monthlyMissedCalls * conversionRate);
const monthlyRevenueLost = recoverableJobs * avgJobValue;
const annualRevenueLost = monthlyRevenueLost * 12;
const roi = Math.round((monthlyRevenueLost - monthlyPrice) / monthlyPrice * 100);

return {
  json: {
    // Company info
    prospectId: prospect.id,
    companyName: f['Company Name'] || 'Your Company',
    contactName: f['Contact Name'] || request.contactName || '',
    city: f['City'] || '',
    state: f['State'] || '',
    phone: f['Phone'] || '',
    email: f['Verified Email'] || '',
    website: f['Website'] || '',

    // Pain points discovered
    painPoints: f['Pain Points'] || '',
    negativeReviews: f['Negative Reviews'] || '',
    hasCommunicationPain: hasCommunicationPain,

    // Discovery notes (from webhook or manual entry)
    discoveryNotes: request.discoveryNotes || '',
    currentChallenges: request.currentChallenges || 'Missed calls, after-hours inquiries, slow follow-up',
    goals: request.goals || 'Never miss a call, book more jobs, increase reviews',

    // Package recommendation
    recommendedPackage: recommendedPackage,
    monthlyPrice: monthlyPrice,
    setupFee: setupFee,

    // ROI calculations
    avgJobValue: avgJobValue,
    missedCallsPerWeek: missedCallsPerWeek,
    monthlyMissedCalls: monthlyMissedCalls,
    recoverableJobs: recoverableJobs,
    monthlyRevenueLost: monthlyRevenueLost,
    annualRevenueLost: annualRevenueLost,
    roi: roi,

    // Timeline
    proposalDate: new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' }),
    validUntil: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })
  }
};

