// Parse and format the proposal
const response = $input.first().json.message?.content || $input.first().json.text || '{}';
let proposal;

try {
  proposal = JSON.parse(response);
} catch (e) {
  const match = response.match(/\{[\s\S]*\}/);
  proposal = match ? JSON.parse(match[0]) : { error: 'Could not parse proposal' };
}

const context = $('Build Proposal Context').first().json;

// Format as HTML for PDF generation
const htmlProposal = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: 'Helvetica Neue', Arial, sans-serif; max-width: 800px; margin: 0 auto; padding: 40px; color: #333; }
    h1 { color: #1a1a2e; border-bottom: 3px solid #4361ee; padding-bottom: 10px; }
    h2 { color: #4361ee; margin-top: 30px; }
    .header { text-align: center; margin-bottom: 40px; }
    .logo { font-size: 28px; font-weight: bold; color: #4361ee; }
    .date { color: #666; margin-top: 10px; }
    .summary { background: #f8f9fa; padding: 20px; border-radius: 8px; margin: 20px 0; }
    .highlight { background: linear-gradient(135deg, #4361ee 0%, #3a0ca3 100%); color: white; padding: 20px; border-radius: 8px; margin: 20px 0; }
    .highlight h3 { margin-top: 0; }
    .roi-box { display: flex; justify-content: space-around; text-align: center; }
    .roi-item { padding: 15px; }
    .roi-number { font-size: 32px; font-weight: bold; }
    .deliverables { background: #f8f9fa; padding: 20px; border-radius: 8px; }
    .deliverables li { margin: 10px 0; }
    .pricing { border: 2px solid #4361ee; border-radius: 8px; padding: 20px; margin: 20px 0; }
    .guarantee { background: #d4edda; border: 1px solid #28a745; padding: 15px; border-radius: 8px; margin: 20px 0; }
    .cta { background: #4361ee; color: white; padding: 20px; border-radius: 8px; text-align: center; margin-top: 30px; }
    .footer { text-align: center; margin-top: 40px; color: #666; font-size: 14px; }
  </style>
</head>
<body>
  <div class="header">
    <div class="logo">HARMONIA</div>
    <p>AI Automation Solutions for HVAC Companies</p>
    <div class="date">Proposal Date: ${context.proposalDate}</div>
  </div>

  <h1>Proposal for ${context.companyName}</h1>
  <p>Prepared for: ${context.contactName || 'Owner/Manager'}</p>

  <div class="summary">
    <h2>Executive Summary</h2>
    <p>${proposal.executiveSummary}</p>
  </div>

  <div class="highlight">
    <h3>The Opportunity</h3>
    <div class="roi-box">
      <div class="roi-item">
        <div class="roi-number">$${context.monthlyRevenueLost.toLocaleString()}</div>
        <div>Monthly Revenue Lost</div>
      </div>
      <div class="roi-item">
        <div class="roi-number">$${context.annualRevenueLost.toLocaleString()}</div>
        <div>Annual Opportunity</div>
      </div>
      <div class="roi-item">
        <div class="roi-number">${context.roi}%</div>
        <div>Projected ROI</div>
      </div>
    </div>
  </div>

  <h2>Current Situation</h2>
  <p>${proposal.situationAnalysis}</p>

  <h2>Proposed Solution</h2>
  <p>${proposal.proposedSolution}</p>

  <div class="deliverables">
    <h2>What You Get</h2>
    <ul>
      ${proposal.deliverables.map(d => `<li>${d}</li>`).join('')}
    </ul>
  </div>

  <div class="pricing">
    <h2>Investment</h2>
    <p>${proposal.investment}</p>
    <table style="width: 100%; margin-top: 15px;">
      <tr>
        <td><strong>Setup Fee (one-time):</strong></td>
        <td style="text-align: right;"><strong>$${context.setupFee.toLocaleString()}</strong></td>
      </tr>
      <tr>
        <td><strong>Monthly Investment:</strong></td>
        <td style="text-align: right;"><strong>$${context.monthlyPrice.toLocaleString()}/month</strong></td>
      </tr>
    </table>
  </div>

  <h2>Timeline</h2>
  <p>${proposal.timeline}</p>

  <div class="guarantee">
    <h2>Our Guarantee</h2>
    <p>${proposal.guarantee}</p>
  </div>

  <div class="cta">
    <h2>Next Steps</h2>
    <p>${proposal.nextSteps}</p>
    <p style="margin-top: 15px;"><strong>This proposal is valid until ${context.validUntil}</strong></p>
  </div>

  <div class="footer">
    <p>Questions? Call us at [YOUR_PHONE] or email [YOUR_EMAIL]</p>
    <p>© ${new Date().getFullYear()} Harmonia - AI That Works While You Sleep</p>
  </div>
</body>
</html>
`;

return {
  json: {
    ...context,
    proposal: proposal,
    htmlProposal: htmlProposal,
    fileName: `Harmonia_Proposal_${context.companyName.replace(/[^a-zA-Z0-9]/g, '_')}_${Date.now()}.html`
  }
};

